import{_ as n,o as a,c as i,ae as h}from"./chunks/framework.BeVX27ge.js";const s=JSON.parse('{"title":"Quản lý Kiến thức","description":"","frontmatter":{},"headers":[],"relativePath":"admin-knowledge.md","filePath":"admin-knowledge.md"}'),e={name:"admin-knowledge.md"};function l(r,t,o,u,d,c){return a(),i("div",null,[...t[0]||(t[0]=[h('<h1 id="quan-ly-kien-thuc" tabindex="-1">Quản lý Kiến thức <a class="header-anchor" href="#quan-ly-kien-thuc" aria-label="Permalink to &quot;Quản lý Kiến thức&quot;">​</a></h1><blockquote><p>Quản lý và tải lên dữ liệu tài liệu để làm nguồn kiến thức chính xác cho Trợ lý.</p></blockquote><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Quản trị viên có thể tải lên, xem, và xóa các tệp kiến thức. Những tài liệu này được chuyển thành vector (công nghệ RAG) để Trợ lý Kiến thức có thể tìm kiếm và trả lời người dùng.</p><blockquote><p>Chỉ dành cho Quản trị viên. <strong>Lưu ý</strong>: Việc quản lý kiến thức hiện tại chủ yếu thông qua API hệ thống. Giao diện frontend đang được phát triển.</p></blockquote><hr><h2 id="tai-len-tai-lieu" tabindex="-1">Tải lên Tài liệu <a class="header-anchor" href="#tai-len-tai-lieu" aria-label="Permalink to &quot;Tải lên Tài liệu&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Định dạng</th><th>Định dạng tệp</th></tr></thead><tbody><tr><td>PDF</td><td>.pdf</td></tr><tr><td>Word</td><td>.docx</td></tr><tr><td>Text</td><td>.txt</td></tr><tr><td>HTML</td><td>.html</td></tr><tr><td>Markdown</td><td>.md</td></tr></tbody></table><h3 id="qua-trinh-xu-ly-tu-đong" tabindex="-1">Quá trình Xử lý Tự động <a class="header-anchor" href="#qua-trinh-xu-ly-tu-đong" aria-label="Permalink to &quot;Quá trình Xử lý Tự động&quot;">​</a></h3><p>Tài liệu Tải lên → Phân tích Tệp → Chia nhỏ Nội dung (Chunking) → Nhúng Vector (Embedding) → Lập Chỉ mục</p><hr><h2 id="xem-co-so-kien-thuc" tabindex="-1">Xem Cơ sở Kiến thức <a class="header-anchor" href="#xem-co-so-kien-thuc" aria-label="Permalink to &quot;Xem Cơ sở Kiến thức&quot;">​</a></h2><p>Quản trị viên có thể xem các khối (chunks) đã tải lên, bao gồm: Tên tệp, Công ty, Phòng ban, Loại khối (TEXT/TABLE/IMAGE), Cập nhật lần cuối...</p><h3 id="phan-ranh-gioi-đa-nguoi-thue-multi-tenant" tabindex="-1">Phân ranh giới Đa người thuê (Multi-tenant) <a class="header-anchor" href="#phan-ranh-gioi-đa-nguoi-thue-multi-tenant" aria-label="Permalink to &quot;Phân ranh giới Đa người thuê (Multi-tenant)&quot;">​</a></h3><ul><li>Dữ liệu hoàn toàn được cách ly theo công ty. Không có sự pha trộn dữ liệu.</li></ul><hr><h2 id="xoa-tai-lieu" tabindex="-1">Xóa Tài liệu <a class="header-anchor" href="#xoa-tai-lieu" aria-label="Permalink to &quot;Xóa Tài liệu&quot;">​</a></h2><p>Quản trị viên có thể xóa hàng loạt thông qua bộ lọc. Dữ liệu khi đã xóa sẽ không còn khả dụng cho Trợ lý Kiến thức (Hành động này không thể hoàn tác).</p>',18)])])}const m=n(e,[["render",l]]);export{s as __pageData,m as default};
